VALUES
  ('disabled-7c4986e7-moex-00066', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-113-e0b1f2ed', 'sub-disabled-7c4986e7-04', NULL, 'single_choice', '甲公司向丁租賃公司承租1台機器設備，合約的內容符合融資租賃。甲公司在 6年的租期中，每年年初須支付租金$110,000，該租金包含每年機器設備的維修 、保險與稅金$20,000。甲公司為取得該租賃發生的原始直接成本為$7,000。承 租人的增額借款利率為 10%，出租人的隱含利率為 8%，甲公司得知隱含利率 。甲公司應認列使用權資產的金額為：（P =3.79079，P =3.99271） 5,10% 5,8%', '["$359,344", "$366,344", "$456,344", "$556,198"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:58+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00067', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-113-e0b1f2ed', 'sub-disabled-7c4986e7-04', NULL, 'single_choice', 'X2年1月1日，甲公司給18位經理每人8,000單位認股權，每單位認股 權得以$60 認購公司普通股 1 股，當時每股普通股的面額為$10，市價為 $82，每單位認股權的公允價值則為$20。每位經理必須在公司內服務滿 4 年，第5年開始得行使認股權。經理如果自得行使日起2年內未行使，其 所持有的認股權就失效。X5 年 7 月 1 日，甲公司有 4 位經理因故離職， X6 年 1 月 1 日則有 9 位經理行使認股權，一直到 X8 年 1 月 1 日都沒有 經理行使認股權。甲公司X5年應認列的酬勞成本為：', '["$72,000", "$80,000", "$88,000", "$168,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:58+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00068', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-113-e0b1f2ed', 'sub-disabled-7c4986e7-04', NULL, 'single_choice', '乙公司於X6年初保留盈餘帳戶餘額為$450,000，X6年相關資料如下：淨 利$1,200,000，現金股利$250,000，庫藏股再發行價格超過成本$100,000， 提撥或有損失準備$250,000，股票股利$150,000。乙公司X6年12月31日 保留盈餘應有的餘額為：', '["$1,000,000", "$1,100,000", "$1,250,000", "$1,400,000 30650"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:58+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00069', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-113-e0b1f2ed', 'sub-disabled-7c4986e7-04', NULL, 'single_choice', '丙公司，X9年12月31日，股本帳戶情況如下： 普通股股本（面額$10） $900,000 5%非累積非參加特別股股本（面額$100） 240,000 8%累積完全參加特別股股本（面額$100） 1,600,000 丙公司於 X5 年 1 月 1 日成立，至 X8 年底止，尚未發放過任何股利。X9 年度丙公司宣告發放股利$764,000。下列關於丙公司 X9 年度之敘述何者 正確？', '["普通股應分配的股利為$86,400", "5%特別股應分配的股利為$15,504", "8%特別股應分配的股利為$640,000", "8%特別股應分配的股利為$663,358"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:58+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00070', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-113-e0b1f2ed', 'sub-disabled-7c4986e7-04', NULL, 'single_choice', '丙公司X1 年銷售1 種附有2 年保證維修期限之玩具狗，依據公司過去經 驗得知有 55%玩具狗不會發生損壞，30%玩具狗會發生小瑕疵，15%玩具 狗則會發生重大瑕疵。每隻玩具狗發生小瑕疵和重大瑕疵時之平均修理費 用分別為$180及$450。丙公司X1年度共銷售200隻玩具狗，每隻售價為 $2,500，X1 年實際發生的免費維修支出$8,500。丙公司X1 年12 月31日 估計產品保證負債餘額為：', '["$0", "$8,500", "$15,800", "$24,300"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:58+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00071', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-113-e0b1f2ed', 'sub-disabled-7c4986e7-04', NULL, 'single_choice', '甲公司X9年度淨利$35,000，部分資產負債表帳戶資料如下： 部分資產負債表帳戶 X9年12月31日 X8年12月31日 應付現金股利 $17,000 $24,000 普通股股本（面額$10） 100,000 90,000 保留盈餘 140,000 120,000 資本公積 25,000 15,000 甲公司X9年支付現金股利金額為：', '["$7,000", "$15,000", "$22,000", "$42,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:58+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00072', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-113-e0b1f2ed', 'sub-disabled-7c4986e7-04', NULL, 'single_choice', '丁公司於X5年11月1日取得A公司普通股20,000股，並分類為「透過 損益按公允價值衡量」之證券投資，成本$530,000，該項投資於 X5 年底 認列金融資產評價損失$30,000。丁公司於 X6 年 2 月 1 日出售 A 公司普 通股 5,000 股，當日每股市價為$36。A 公司於 X6 年 8 月 30 日宣告並發 放股票股利4%，X6年底普通股每股市價為$34。丁公司X6年度綜合損益 表中，因持有A公司股票所產生損益為：', '["$135,000", "$155,000", "$155,400", "$210,400 30650"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:58+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00073', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-113-e0b1f2ed', 'sub-disabled-7c4986e7-04', NULL, 'single_choice', '丙公司債券投資相關資料如下： 公允價值 成本 X5年底 X6年底 透過損益按公允價值衡量 $350,000 $340,000 $450,000 按攤銷後成本衡量 290,000 270,000 250,000 丙公司X6年綜合損益表內，金融資產評價利益為：', '["$60,000", "$90,000", "$100,000", "$110,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:58+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00074', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-113-e0b1f2ed', 'sub-disabled-7c4986e7-04', NULL, 'single_choice', '乙公司X5年1月1日購入1台設備，該設備定價$105,000，付款條件3/10 ，n/30，乙公司X5年1月14日支付價款。該設備購入當天，乙公司亦支 付下列費用：運費$3,000、搬運途中不慎損壞之修理費用$2,200、安裝費 $1,950、試車費$1,200。該設備估計可用5年，殘值$3,000，使用年數合計 法提列折舊。X7 年1 月1 日，該設備進行重大修理支出$30,000，估計大 修後尚可再使用5年，無殘值。乙公司X7年度的折舊費用為：', '["$15,000", "$24,400", "$25,000", "$25,420"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:58+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00075', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-113-e0b1f2ed', 'sub-disabled-7c4986e7-04', NULL, 'single_choice', '由於經營環境改變，乙公司認為生產電視機的設備價值可能發生減損。該 設備於X1年12月31日之相關資料為：成本$1,000,000，累計折舊（截至 X1 年12 月31 日）$520,000，淨公允價值$230,000，使用價值$240,000， 該設備預計尚可使用5年，無殘值，使用年數合計法提列折舊。該設備至 X2 年底仍未出售，淨公允價值$295,000，使用價值$315,000。乙公司 X2 年底該設備應認列的減損迴轉利益為：', '["$75,000", "$155,000", "$160,000", "$240,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:58+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL)
